    if (*(int *)(self + 0x48) == 2) {
        sp1C = 1000;
        v1 = *(char **)(*(char **)(self + 0x44) + (idx ^ 1) * 0x60);
        v0 = *(char **)(v1 + 0x28);
        if (v0) {}
        (*(void (**)(char *, int *, char *))(v0 + 0x2C))((char *)((int)*(short *)(v0 + 0x28) + (int)v1), &sp1C, self);
    }
